import React, { useState } from "react";
import { Bar, Line, Pie } from "react-chartjs-2";


const Charts = () => {
  const [activeChart, setActiveChart] = useState("bar");

  const salaryByRole = {
    labels: ["Developer", "Data Scientist", "Tester"],
    datasets: [
      {
        label: "Salary",
        data: [40000, 60000, 30000],
        backgroundColor: ["#4facfe", "#00f2fe", "#43e97b"],
      },
    ],
  };

  const experienceData = {
    labels: [1, 2, 3, 4, 5],
    datasets: [
      {
        label: "Salary Growth",
        data: [20000, 30000, 45000, 60000, 80000],
        borderColor: "#4facfe",
      },
    ],
  };

  const skillsData = {
    labels: ["Python", "Java", "ML", "Others"],
    datasets: [
      {
        data: [30, 25, 25, 20],
        backgroundColor: ["#667eea", "#764ba2", "#43e97b", "#f093fb"],
      },
    ],
  };

  return (
    <div style={{ marginTop: "40px", textAlign: "center" }}>
      
      <h2>📊 Analytics Dashboard</h2>

      {/* 🔥 Tabs */}
      <div style={{ marginBottom: "20px" }}>
        <button onClick={() => setActiveChart("bar")}>Salary by Role</button>
        <button onClick={() => setActiveChart("line")}>Experience Trend</button>
        <button onClick={() => setActiveChart("pie")}>Skills</button>
      </div>

      {/* 🔥 Show Only One Chart */}
      <div style={{ maxWidth: "600px", margin: "auto" }}>
        {activeChart === "bar" && <Bar data={salaryByRole} />}
        {activeChart === "line" && <Line data={experienceData} />}
        {activeChart === "pie" && <Pie data={skillsData} />}
      </div>

    </div>
  );
};

export default Charts;
